// For list picker responses, Twilio sends the item title or ListPick:item_id
// For quick reply, Twilio sends the button title
function getChoice(text) {
  const t = text.trim();
  if (/^[1-4]$/.test(t)) return parseInt(t);
  // Match by list picker ID format
  const idMatch = t.match(/^(\d+)$/);
  if (idMatch) return parseInt(idMatch[1]);
  // Match by content
  if (t.includes('הסתפרתי') || t.includes('כמה שצריך') || t.includes('10,000') || t.includes('10000') || t.includes('יודעים ותומכים')) return 4;
  if (t.includes('תקופה') || t.includes('עוקב') || t.includes('8-10') || t.includes('7000') || t.includes('7,000') || t.includes('מעל 15') || t.includes('ראיתי הכל') || t.includes('יודעים') || t.includes('שכנוע') || t.includes('ערב')) return 3;
  if (t.includes('מזמן') || t.includes('סרטונים') || t.includes('צפיתי') || t.includes('6-7') || t.includes('4500') || t.includes('4,500') || t.includes('חברים') || t.includes('ראיתי קצת') || t.includes('זרקתי') || t.includes('טלפון') || t.includes('צהריים')) return 2;
  if (t.includes('שמעתי') || t.includes('השבוע') || t.includes('אין לי') || t.includes('3-4') || t.includes('1500') || t.includes('1,500') || t.includes('לא ראיתי') || t.includes('לא סיפרתי') || t.includes('לא היה') || t.includes('זום') || t.includes('בוקר')) return 1;
  return null;
}

if (currentState === 'DONE') {
  _skip = true;
} else switch(currentState) {

  case 'WAIT_CONFIRM': {
    state = 'ASK_AGE';
    responseMsg = 'מעולה! בן כמה אתה?';
    break;
  }

  case 'ASK_AGE': {
    const m = message.match(/\d+/);
    if (!m) { responseMsg = 'לא הצלחתי לזהות גיל 😅 תכתוב לי רק את המספר'; break; }
    const ageVal = parseInt(m[0]);
    answers.age = ageVal;
    age = ageVal;
    if (ageVal <= 11) {
      _disqualified = true;
      responseMsg = 'הבנתי, מצטער אבל הכניסה לאקדמיה היא מגיל 13 ורק חריגים בגיל 12.\nנשמח לשמוע ממך בהמשך :)';
      status = 'disqualified';
      state = 'DISQUALIFIED';
      break;
    }
    if (ageVal === 12) score += 1;
    else if (ageVal <= 14) score += 3;
    else score += 5;
    state = 'ASK_FAMILIARITY';
    contentSid = TEMPLATES['ASK_FAMILIARITY'];
    break;
  }

  case 'ASK_FAMILIARITY': {
    const c = getChoice(msg);
    if (!c) { contentSid = TEMPLATES['ASK_FAMILIARITY']; break; }
    score += {1:0, 2:1, 3:2, 4:4}[c];
    answers.familiarity = c;
    state = 'ASK_EXPERIENCE';
    contentSid = TEMPLATES['ASK_EXPERIENCE'];
    break;
  }

  case 'ASK_EXPERIENCE': {
    const c = getChoice(msg);
    if (!c) { contentSid = TEMPLATES['ASK_EXPERIENCE']; break; }
    answers.experience = c;
    if (c >= 3) has_experience = true;
    state = 'ASK_UNDERSTANDING';
    contentSid = TEMPLATES['ASK_UNDERSTANDING'];
    break;
  }

  case 'ASK_UNDERSTANDING': {
    const c = getChoice(msg);
    if (!c || c > 3) { contentSid = TEMPLATES['ASK_UNDERSTANDING']; break; }
    score += {1:0, 2:0.5, 3:2}[c];
    answers.understanding = c;
    state = 'ASK_HOURS';
    contentSid = TEMPLATES['ASK_HOURS'];
    break;
  }

  case 'ASK_HOURS': {
    const c = getChoice(msg);
    if (!c) { contentSid = TEMPLATES['ASK_HOURS']; break; }
    score += {1:0, 2:1, 3:2, 4:4}[c];
    answers.hours = c;
    state = 'ASK_BUDGET';
    contentSid = TEMPLATES['ASK_BUDGET'];
    break;
  }

  case 'ASK_BUDGET': {
    const c = getChoice(msg);
    if (!c) { contentSid = TEMPLATES['ASK_BUDGET']; break; }
    score += {1:-2, 2:1, 3:2, 4:2}[c];
    answers.budget = c;
    const ageVal = answers.age || 0;
    if (ageVal >= 12 && ageVal <= 18) {
      state = 'ASK_PARENTS';
      contentSid = TEMPLATES['ASK_PARENTS'];
    } else {
      state = 'ASK_MEETING_INTRO';
      contentSid = TEMPLATES['ASK_MEETING_INTRO'];
    }
    break;
  }

  case 'ASK_PARENTS': {
    const c = getChoice(msg);
    if (!c) { contentSid = TEMPLATES['ASK_PARENTS']; break; }
    score += {1:0, 2:0, 3:1, 4:3}[c];
    answers.parents = c;
    state = 'ASK_MEETING_INTRO';
    contentSid = TEMPLATES['ASK_MEETING_INTRO'];
    break;
  }

  case 'ASK_MEETING_INTRO': {
    const c = getChoice(msg);
    if (!c || c > 2) { contentSid = TEMPLATES['ASK_MEETING_INTRO']; break; }
    meeting_type = c === 1 ? 'זום' : 'טלפון';
    answers.meetingType = meeting_type;
    state = 'ASK_AVAILABILITY';
    contentSid = TEMPLATES['ASK_AVAILABILITY'];
    break;
  }

  case 'ASK_AVAILABILITY': {
    const c = getChoice(msg);
    if (!c || c > 3) { contentSid = TEMPLATES['ASK_AVAILABILITY']; break; }
    availability = {1:'בוקר (9-12)', 2:'צהריים (12-16)', 3:'ערב (16-20)'}[c];
    answers.availability = availability;
    lead_type = score >= 16 ? 'hot' : score >= 10 ? 'warm' : 'cold';
    answers.finalScore = score;
    answers.leadType = lead_type;
    state = 'DONE';
    status = 'completed';
    _done = true;
    completed_at = new Date().toISOString();
    responseMsg = 'העברתי אותך לשלב הבא!\nיחזרו אליך לקביעת שיחת התאמה בהקדם האפשרי ובהתאם למקום פנוי🤝';
    break;
  }

  default:
    _skip = true;
}

