const callbackUrl =  `https://alon09.app.n8n.cloud/webhook/call-completed?leadPhone=${encodeURIComponent(leadPhone)}&amp;leadId=${encodeURIComponent(leadId)}`;

const twiml = `<Response><Say language="he-IL" voice="alice">שלום, אנחנו מחברים אתכם כעת ללקוח. אנא המתינו.</Say><Dial record="record-from-answer" recordingStatusCallback="${callbackUrl}" recordingStatusCallbackMethod="POST"><Number>+${leadPhone}</Number></Dial></Response>`;

return [{ json: { leadId, leadPhone, agentPhone, authHeader, twiml } }];

const crypto = require('crypto');

// ⚠️ REPLACE THIS WITH YOUR ZOOM SECRET TOKEN
// Found in: Zoom Marketplace App → Feature tab → Event Subscriptions → Secret Token
const ZOOM_SECRET_TOKEN = 'YOUR_ZOOM_SECRET_TOKEN';

const body = $input.first().json.body || $input.first().json;

// ── Zoom CRC Challenge ──────────────────────────────────────
// Zoom sends this when you click 'Validate' to verify your URL
if (body.event === 'endpoint.url_validation') {
  const plainToken = body.payload?.plainToken || '';
  const encryptedToken = crypto
    .createHmac('sha256', ZOOM_SECRET_TOKEN)
    .update(plainToken)
    .digest('hex');
  return [{
    json: {
      isCRC: true,
      plainToken: plainToken,
      encryptedToken: encryptedToken
    }
  }];
}

// ── Recording Completed Event ───────────────────────────────
if (body.event !== 'recording.completed') {
  return [{ json: { isCRC: false, skip: true, reason: 'Ignored event: ' + body.event } }];
}

const obj = body.payload?.object;
if (!obj) {
  return [{ json: { isCRC: false, skip: true, reason: 'Missing payload.object' } }];
}

const duration = obj.duration;
if (!duration || duration < 4) {
  return [{ json: { isCRC: false, skip: true, reason: `Call too short: ${duration} min` } }];
}

const recordingFiles = obj.recording_files || [];
const vttFile = recordingFiles.find(
  f => f.file_type === 'TRANSCRIPT' || f.file_type === 'VTT'
);

if (!vttFile || !vttFile.download_url) {
  return [{ json: { isCRC: false, skip: true, reason: 'No transcript file in recording_files' } }];
}

const hostEmail = (obj.host_email || '').toLowerCase().trim();
const participants = (obj.participants || []).filter(
  p => p.email && p.email.toLowerCase().trim() !== hostEmail
);

return [{
  json: {
    isCRC: false,
    skip: false,
    meetingId: obj.id || '',
    meetingTopic: obj.topic || '',
    duration: duration,
    transcriptUrl: vttFile.download_url,
    downloadToken: body.download_token || '',
    participants: participants,
    hostEmail: hostEmail
  }
}];

const rawVtt = $input.first().json.data || '';
const prevData = $('Handle CRC or Extract').first().json;

const lines = rawVtt.split('\n');
const textLines = [];

for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed || trimmed === 'WEBVTT' || trimmed.startsWith('NOTE ')) continue;
  if (/^\d{2}:\d{2}:\d{2}\.\d{3}\s*-->\s*\d{2}:\d{2}:\d{2}\.\d{3}/.test(trimmed)) continue;
  if (/^\d+$/.test(trimmed)) continue;
  textLines.push(trimmed);
}

const transcriptText = textLines.join('\n').replace(/\n{3,}/g, '\n\n').trim();

return [{
  json: {
    meetingId: prevData.meetingId,
    meetingTopic: prevData.meetingTopic,
    duration: prevData.duration,
    participants: prevData.participants,
    transcriptText: transcriptText || '(Transcript was empty or could not be parsed)'
  }
}];

const allItems = $input.all();
let allLeads = [];
if (allItems.length === 1 && Array.isArray(allItems[0].json)) {
  allLeads = allItems[0].json;
} else if (allItems.length === 1 && allItems[0].json && Array.isArray(allItems[0].json.data)) {
  allLeads = allItems[0].json.data;
} else {
  allLeads = allItems.map(i => i.json);
}
if (allLeads.length > 0 && allLeads[0].json) {
  allLeads = allLeads.map(i => i.json);
}

const workflowData = $('Parse VTT').first().json;
const participants = workflowData.participants || [];

const participantEmails = participants
  .map(p => (p.email || '').toLowerCase().trim())
  .filter(Boolean);

let matchedLead = null;
for (const email of participantEmails) {
  matchedLead = allLeads.find(
    l => l.email && l.email.toLowerCase().trim() === email
  );
  if (matchedLead) break;
}

if (!matchedLead) {
  return [{
    json: {
      ...workflowData,
      leadFound: false,
      debugInfo: `Checked: ${participantEmails.join(', ')} | Leads count: ${allLeads.length}`
    }
  }];
}

return [{
  json: {
    ...workflowData,
    leadFound: true,
    leadPhone: matchedLead.phone || '',
    leadName: matchedLead.name || '',
    leadEmail: matchedLead.email || ''
  }
}];

